local mode = "Loop"
local t = 0
local idx = 1
local lastValidCFrame = cam.CFrame
local lastTime = frames[#frames].Time
local function smoothCFrame(a, b, alpha)
    local pos = a.Position:Lerp(b.Position, alpha)
    local lookA = a.LookVector
    local lookB = b.LookVector
    local upA = a.UpVector
    local upB = b.UpVector
    local look = lookA:Lerp(lookB, alpha)
    if look.Magnitude < 0.0001 then look = (a.LookVector + b.LookVector).Unit else look = look.Unit end
    local up = upA:Lerp(upB, alpha).Unit
    local right = look:Cross(up)
    if right.Magnitude < 0.0001 then right = look:Cross(Vector3.new(0,1,0)).Unit else right = right.Unit end
    up = right:Cross(look).Unit
    return CFrame.fromMatrix(pos, right, up)
end
RunService.RenderStepped:Connect(function(dt)
    t = t + dt
    if mode == "Once" then
        if t > lastTime then
            cam.CFrame = lastValidCFrame
            return
        end
    else
        t = t % lastTime
    end
    while idx < #frames and t >= frames[idx + 1].Time do
        idx = idx + 1
    end
    if idx >= #frames or (mode == "Loop" and t < frames[idx].Time) then
        idx = 1
    end
    local a = frames[idx]
    local b = frames[idx + 1] or frames[1]
    local alpha = (t - a.Time) / (b.Time - a.Time)
    alpha = math.clamp(alpha, 0, 1)
    local pos = a.Pos:Lerp(b.Pos, alpha)
    local vel = a.Vel:Lerp(b.Vel, alpha)
    local move = a.Move:Lerp(b.Move, alpha)
    local fov = a.FOV + (b.FOV - a.FOV) * alpha
    local cf = smoothCFrame(a.CFrame, b.CFrame, alpha)
    lastValidCFrame = cf
    cam.CFrame = cf
    cam.FieldOfView = fov
    local lookFlat = Vector3.new(cf.LookVector.X, 0, cf.LookVector.Z)
    if lookFlat.Magnitude > 0 then
        lookFlat = lookFlat.Unit
        hrp.CFrame = CFrame.new(pos, pos + lookFlat * 10)
    end
    hum:Move(move, true)
    hrp.AssemblyLinearVelocity = vel
end)
